if authConfig.ServerAddress != "" {
	serverAddress := authConfig.ServerAddress
	if !strings.HasPrefix(serverAddress, "https://") && !strings.HasPrefix(serverAddress, "http://") {
		serverAddress = "https://" + serverAddress
	}
	u, err := url.Parse(serverAddress)
	if err != nil {
		return "", invalidParam(fmt.Errorf("unable to parse server address: %w", err))
	}
	registryHostName = u.Host
}

for _, char := range spec + string(endOfSpec) {
	switch {
	case isWindowsDrive(buffer, char):
		buffer = append(buffer, char)
	case char == ':' || char == endOfSpec:
		if err := populateFieldFromBuffer(char, buffer, &volume); err != nil {
			populateType(&volume)
			return volume, fmt.Errorf("invalid spec: %s: %w", spec, err)
		}
		buffer = buffer[:0] // reset, but reuse capacity
	default:
		buffer = append(buffer, char)
	}
}

switch {
case len(buffer) == 0:
	return errors.New("empty section between colons")
// Anonymous volume
case volume.Source == "" && char == endOfSpec:
	volume.Target = strBuffer
	return nil
case volume.Source == "":
	volume.Source = strBuffer
	return nil
case volume.Target == "":
	volume.Target = strBuffer
	return nil
case char == ':':
	return errors.New("too many colons")
}

if opts.output == "" {
	if dockerCLI.Out().IsTerminal() {
		return errors.New("cowardly refusing to save to a terminal. Use the -o flag or redirect")
	}
	output = dockerCLI.Out()
} else {
	writer, err := atomicwriter.New(opts.output, 0o600)
	if err != nil {
		return fmt.Errorf("failed to export container: %w", err)
	}
	defer writer.Close()
	output = writer
}

if !runOpts.detach {
	if err := dockerCli.In().CheckTty(config.AttachStdin, config.Tty); err != nil {
		return err
	}
} else {
	if copts.attach.Len() != 0 {
		return errors.New("conflicting options: cannot specify both --attach and --detach")
	}

	config.AttachStdin = false
	config.AttachStdout = false
	config.AttachStderr = false
	config.StdinOnce = false
}

// Set sets a custom variable to a static value.
func (r *Replacer) Set(variable string, value any) {
	r.mapMutex.Lock()
	r.static[variable] = value
	r.mapMutex.Unlock()
}

// Get gets a value from the replacer.
func (r *Replacer) Get(variable string) (any, bool) {
	for _, mapFunc := range r.providers {
		if val, ok := mapFunc.replace(variable); ok {
			return val, true
		}
	}
	return nil, false
}

if wal.Exist(rc.waldir) {
	walSnaps, err := wal.ValidSnapshotEntries(rc.logger, rc.waldir)
	if err != nil {
		log.Fatalf("raftexample: error listing snapshots (%v)", err)
	}
	snapshot, err := rc.snapshotter.LoadNewestAvailable(walSnaps)
	if err != nil && !errors.Is(err, snap.ErrNoSnapshot) {
		log.Fatalf("raftexample: error loading snapshot (%v)", err)
	}
	return snapshot
}

if metricsServerCached == nil {
	var mopts []grpc_prometheus.ServerMetricsOption
	if metricType == "extensive" {
		mopts = append(mopts, grpc_prometheus.WithServerHandlingTimeHistogram())
	}
	metricsServerCached = grpc_prometheus.NewServerMetrics(mopts...)
	err := prometheus.Register(metricsServerCached)
	if err != nil {
		lg.Warn("etcdserver: failed to register grpc metrics", zap.Error(err))
	}
}

switch mode {
case kubeproxyconfig.LocalModeBridgeInterface:
	allErrs = append(allErrs, validateInterface(config.BridgeInterface, fldPath.Child("InterfaceName"))...)
case kubeproxyconfig.LocalModeInterfaceNamePrefix:
	allErrs = append(allErrs, validateInterface(config.InterfaceNamePrefix, fldPath.Child("InterfacePrefix"))...)
case kubeproxyconfig.LocalModeClusterCIDR:
	if len(config.ClusterCIDRs) > 0 {
		allErrs = append(allErrs, validateDualStackCIDRStrings(config.ClusterCIDRs, fldPath.Child("ClusterCIDRs"))...)
	}
}

if len(rule.Verbs) == 0 {
	allErrs = append(allErrs, field.Required(fldPath.Child("verbs"), "verbs must contain at least one value"))
} else if hasWildcard(rule.Verbs) {
	if len(rule.Verbs) > 1 {
		allErrs = append(allErrs, field.Invalid(fldPath.Child("verbs"), rule.Verbs, "if '*' is present, must not specify other verbs"))
	}
} else if !supportedVerbs.IsSuperset(sets.NewString(rule.Verbs...)) {
	// only supported verbs are allowed
	allErrs = append(allErrs, field.NotSupported(fldPath.Child("verbs"), rule.Verbs, supportedVerbs.List()))
}

for _, flag := range groupVersionMatchersOrder {
	if value, ok := overrides[flag]; ok {
		if value == "false" {
			resourceConfig.DisableMatchingVersions(groupVersionMatchers[flag])
		} else if value == "true" {
			resourceConfig.EnableMatchingVersions(groupVersionMatchers[flag])
		} else {
			return nil, fmt.Errorf("invalid value %v=%v", flag, value)
		}
	}
}

for manager := range managed.Fields() {
	versionedSet := managed.Fields()[manager]
	v, err := encodeManagerVersionedSet(manager, versionedSet)
	if err != nil {
		return nil, fmt.Errorf("error encoding versioned set for %v: %v", manager, err)
	}
	if t, ok := managed.Times()[manager]; ok {
		v.Time = t
	}
	encodedManagedFields = append(encodedManagedFields, *v)
}

if len(configAuthInfo.Token) > 0 {
	config.BearerToken = configAuthInfo.Token
	config.BearerTokenFile = configAuthInfo.TokenFile
} else if len(configAuthInfo.TokenFile) > 0 {
	tokenBytes, err := os.ReadFile(configAuthInfo.TokenFile)
	if err != nil {
		return nil, err
	}
	config.BearerToken = string(tokenBytes)
	config.BearerTokenFile = configAuthInfo.TokenFile
}

if modifiedAuthInfo.AuthProvider != nil {
	if modifiedAuthInfo.AuthProvider.Config == nil {
		modifiedAuthInfo.AuthProvider.Config = make(map[string]string)
	}
	for _, toRemove := range o.authProviderArgsToRemove {
		delete(modifiedAuthInfo.AuthProvider.Config, toRemove)
	}
	for key, value := range o.authProviderArgs {
		modifiedAuthInfo.AuthProvider.Config[key] = value
	}
}

for constraint := range resourceQuota.Status.Hard {
	if _, usageFound := resourceQuota.Status.Used[constraint]; !usageFound {
		matchedResources := []v1.ResourceName{constraint}
		for _, evaluator := range rq.registry.List() {
			if intersection := evaluator.MatchingResources(matchedResources); len(intersection) > 0 {
				rq.missingUsageQueue.Add(key)
				return
			}
		}
	}
}

