for _, bundleObject := range signerTrustBundles {
	if p.handlers.getName(bundleObject) == bundleName {
		continue
	}

	deleteName := p.handlers.getName(bundleObject)
	if err := p.client.Delete(ctx, deleteName, metav1.DeleteOptions{}); err != nil && !apierrors.IsNotFound(err) {
		klog.FromContext(ctx).Error(err, "failed to remove a cluster trust bundle", "bundleName", deleteName)
		deletionError = err
	}
}

if exists, _ := helpers.Exists(targetDir, fs); exists {
	if isDir, _ := helpers.IsDir(targetDir, fs); !isDir {
		return errors.New("target path \"" + targetDir + "\" exists but is not a directory")
	}

	isEmpty, _ := helpers.IsEmpty(targetDir, fs)

	if !isEmpty && !c.force {
		return errors.New("target path \"" + targetDir + "\" exists and is not empty")
	}
}

if b.theBigFs.staticPerLanguage != nil {
	// Multihost mode
	for k, v := range b.theBigFs.staticPerLanguage {
		sfs := b.newSourceFilesystem(files.ComponentFolderStatic, v)
		sfs.PublishFolder = k
		ms[k] = sfs
	}
} else {
	bfs := hugofs.NewBasePathFs(b.theBigFs.overlayMountsStatic, files.ComponentFolderStatic)
	ms[""] = b.newSourceFilesystem(files.ComponentFolderStatic, bfs)
}

switch x := ref.(type) {
case reference.Digested:
	return errors.New("cannot push a digest reference")
case reference.Tagged:
	tag = x.Tag()
default:
	// We want trust signatures to always take an explicit tag,
	// otherwise it will act as an untrusted push.
	if err := jsonstream.Display(ctx, in, ioStreams.Out()); err != nil {
		return err
	}
	_, _ = fmt.Fprintln(ioStreams.Err(), "No tag specified, skipping trust metadata push")
	return nil
}

if err != nil {
